// При срабатывании inject, наполнить базу примерами.
const docs = (msg.payload && msg.payload.documents) || [
    'Node-RED - это инструмент для визуального программирования, основанный на Node.js. Он используется для построения потоков данных (flows) между устройствами IoT, API и онлайн-сервисами.',
    'LangChain - фреймворк для разработки приложений на базе больших языковых моделей (LLM). Поддерживает chains, agents, RAG, memory.',
    'MCP (Model Context Protocol) - открытый протокол Anthropic для подключения LLM к внешним инструментам и источникам данных.',
    'ReAct - паттерн рассуждения, в котором LLM чередует Thought/Action/Observation для решения многошаговых задач.',
];
const vsNode = RED.nodes.getNode('vs-rag');
if (!vsNode) {
    node.error('vs-rag нода не найдена');
    return done();
}
const raw = vsNode.context().global.get('langchain_vs_kb-main') || [];
vsNode.context().global.set('langchain_vs_kb-main', raw.concat(docs));
msg.payload = { ok: true, added: docs.length, total: raw.length + docs.length };
node.send(msg);
done();
return;
